SELECT m.*, ste.site_nm AS site_nm, ord.member_nm AS order_nm, pay.vbank_bank_nm AS pay_nm, cd_pm.code_label AS pay_method_cd_nm, cd_rs.code_label AS refund_status_cd_nm FROM od_refund_method m LEFT JOIN sy_site ste ON ste.site_id = m.site_id LEFT JOIN od_order ord ON ord.order_id = m.order_id LEFT JOIN od_pay pay ON pay.pay_id = m.pay_id LEFT JOIN sy_code cd_pm ON cd_pm.code_grp = 'PAY_METHOD' AND cd_pm.code_value = m.pay_method_cd LEFT JOIN sy_code cd_rs ON cd_rs.code_grp = 'REFUND_STATUS' AND cd_rs.code_value = m.refund_status_cd
ORDER BY m.refund_method_id ASC ORDER BY m.refund_method_id DESC ORDER BY m.reg_date ASC ORDER BY m.reg_date DESC ORDER BY m.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

