UPDATE od_refund_method
site_id = #{siteId}, refund_id = #{refundId}, order_id = #{orderId}, pay_method_cd = #{payMethodCd}, refund_priority = #{refundPriority}, refund_amt = #{refundAmt}, refund_avail_amt = #{refundAvailAmt}, refund_status_cd = #{refundStatusCd}, refund_status_cd_before = #{refundStatusCdBefore}, refund_date = #{refundDate}, pay_id = #{payId}, pg_refund_id = #{pgRefundId}, pg_response = #{pgResponse}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE refund_method_id = #{refundMethodId}
